"use strict";const fileInput=document.getElementById("file-upload"),uploadButton=document.getElementById("upload-button"),sourceInput=document.getElementById("file-source"),tagTextarea=document.getElementById("file-tags"),ratingRadios=document.getElementsByName("rating");function getRating(){for(let i=0;i<ratingRadios.length;i++)if(ratingRadios[i].checked)return ratingRadios[i].value}function displayImage(input){if(input.files&&input.files[0]){var reader=new FileReader;reader.onload=function(e){$("#preview-image").attr("src",e.target.result)},reader.readAsDataURL(input.files[0])}}uploadButton.onclick=function(){if(fileInput.files.length<=0)return void alert("Please select a file to upload.");let formdata=new FormData;formdata.append("file",fileInput.files[0]),formdata.append("source",sourceInput.value),formdata.append("tags",tagTextarea.value.replace(/ /g,"_").split("\n")),formdata.append("rating",getRating()),fetch("/api/upload",{method:"POST",body:formdata}).then(response=>response.json()).then(result=>{result.ok?location.href=result.path:alert(result.error)}).catch(error=>alert(error))};